CREATE OR REPLACE VIEW view_tel_det_lon (membership_no, loan_contract_no, begining_of_contract, loan_approve_amount, loan_installment_amount, period_payment_amount, last_calcint_date, last_access_date, tran_to_coll, last_period, principal_balance, year_total_interest, interest_arrear, loan_type, close_status, atm_status, loan_looping, loan_group, loan_group_code, pay_loan_period, drop_payment_status, pending_amount, cal_shr_auto, atm_balance) AS select tb.MEMBERSHIP_NO,tb.LOAN_CONTRACT_NO,tb.BEGINING_OF_CONTRACT,tb.LOAN_APPROVE_AMOUNT,tb.LOAN_INSTALLMENT_AMOUNT,tb.PERIOD_PAYMENT_AMOUNT,tb.LAST_CALCINT_DATE,tb.LAST_ACCESS_DATE,tb.TRAN_TO_COLL,tb.LAST_PERIOD,tb.PRINCIPAL_BALANCE,tb.YEAR_TOTAL_INTEREST,tb.INTEREST_ARREAR,tb.LOAN_TYPE,tb.CLOSE_STATUS,tb.ATM_STATUS,tb.LOAN_LOOPING,tb.LOAN_GROUP,tb.LOAN_GROUP_CODE,tb.PAY_LOAN_PERIOD,tb.DROP_PAYMENT_STATUS,tb.PENDING_AMOUNT,tb.CAL_SHR_AUTO,tb.ATM_BALANCE
  FROM
    
  ( 
  select   sc_lon_m_contract.membership_no ,
        sc_lon_m_contract.loan_contract_no,
        sc_lon_m_contract.begining_of_contract,
        sc_lon_m_contract.loan_approve_amount,        
        sc_lon_m_contract.loan_installment_amount ,
        CASE WHEN  sc_lon_m_rule.drop_all ='1' THEN  0   ELSE sc_lon_m_contract.period_payment_amount END  as period_payment_amount,
        sc_lon_m_loan_card.last_calcint_date,
        sc_lon_m_loan_card.last_access_date,
        sc_lon_m_contract.tran_to_coll,
        sc_lon_m_loan_card.last_period,
        sc_lon_m_loan_card.principal_balance,
        sc_lon_m_loan_card.year_total_interest,        
        sc_lon_m_loan_card.interest_arrear,
        sc_lon_m_loan_card.loan_type, 
        sc_lon_m_loan_card.close_status,
        sc_lon_m_rule.atm_status,
        sc_lon_m_rule.loan_looping,       
       '0' as loan_group,  


        sc_lon_m_rule.loan_group_code,
        sc_lon_m_rule.pay_loan_period,
        sc_lon_m_loan_card.drop_payment_status ,
        sc_lon_m_loan_card.pending_amount
        ,sc_lon_m_contract.cal_shr_auto 
        ,CASE WHEN sc_lon_m_rule.atm_status                ='1' THEN  CASE WHEN  sc_lon_m_contract.cal_shr_auto ='1' THEN  'UP : '   ELSE '' END  || pka_mem_det.fp_atm_balance(sc_lon_m_contract.loan_contract_no)                  ELSE pka_mem_det.fp_loan_det(sc_lon_m_contract.loan_contract_no) END   as atm_balance

    from sc_lon_m_contract,
      sc_lon_m_loan_card,
      sc_lon_m_rule
    where ( sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no )
    and ( sc_lon_m_loan_card.loan_type = sc_lon_m_rule.loan_type )

and ( sc_lon_m_loan_card.principal_balance <> 0 or ( sc_lon_m_rule.atm_status = '1' and  sc_lon_m_loan_card.close_status = '0' ) ) 


union all

--Keep Coll
select   sc_lon_m_contract_coll.ref_own_no as membership_no  ,     
        sc_lon_m_contract.loan_contract_no,
        sc_lon_m_contract.begining_of_contract,
        sc_lon_m_contract.loan_approve_amount,                           
        sc_lon_m_contract.loan_installment_amount ,
        sc_lon_m_contract.period_payment_amount as period_payment_amount ,
        sc_lon_m_loan_card.last_calcint_date,
        sc_lon_m_loan_card.last_access_date,
        '1' as tran_to_coll,
        sc_lon_m_loan_card.last_period,
        sc_lon_m_loan_card.principal_balance,
        sc_lon_m_loan_card.year_total_interest,

        sc_lon_m_loan_card.interest_arrear,
        sc_lon_m_loan_card.loan_type, 

        sc_lon_m_loan_card.close_status,
        '' as atm_status,
         '' as loan_looping,

        '1' as loan_group,        

        '''' as loan_group_code,
        '' as pay_loay_loan_period,
        sc_lon_m_loan_card.drop_payment_status ,
        0 as pending_amount
        ,'0' as cal_shr_auto 
        ,'เป็นของ ' || sc_lon_m_contract.membership_no  as atm_balance
from sc_lon_m_contract_coll
,sc_lon_m_loan_card
,sc_lon_m_contract
,sc_mem_m_membership_registered
where 1=1
and sc_lon_m_contract_coll.status = '0'
and sc_mem_m_membership_registered.member_status_code = '3'
and sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract_coll.loan_contract_no
and sc_lon_m_loan_card.loan_contract_no =  sc_lon_m_contract.loan_contract_no
and sc_lon_m_loan_card.membership_no = sc_mem_m_membership_registered.membership_no
and sc_lon_m_loan_card.principal_balance > 0 
and sc_lon_m_contract_coll.collateral_type_code = '01'
) tb 
where 1=1
--and membership_no = '047276'  --atm 
